      getCalendarEvents(startDate: $startDate, endDate: $endDate, query: $query, regionType: $regionType, regionId: $regionId, disciplineId: $disciplineId, rankingCategoryId: $rankingCategoryId, permitLevelId: $permitLevelId, competitionGroupId: $competitionGroupId, competitionSubgroupId: $competitionSubgroupId, limit: $limit, offset: $offset) {
        results { id name dateRange venue area rankingCategory disciplines competitionGroup competitionSubgroup hasResults }
        parameters { count }
